package pe.edu.untels.controllers;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import pe.edu.untels.dtos.LoginRequestDTO;
import pe.edu.untels.dtos.LoginResponseDTO;
import pe.edu.untels.servicesinterfaces.IUserService;

@RestController
@RequestMapping("/api/auth")
public class AuthController {
    @Autowired
    private IUserService userService;

    @PostMapping("/login")
    public ResponseEntity<?> login(@RequestBody LoginRequestDTO loginRequestDTO) {
        try {
            LoginResponseDTO response = userService.login(loginRequestDTO);
            return ResponseEntity.ok(response);
        } catch (Exception e) {
            return ResponseEntity.status(401).body("Credenciales inválidas");
        }
    }

    @GetMapping("/validate-role/{idUser}")
    public ResponseEntity<?> validateRole(@PathVariable int idUser) {
        try {
            var userOpt = userService.getUserById(idUser);
            if (userOpt.isPresent()) {
                String role = userOpt.get().getRole().getNameRole();
                return ResponseEntity.ok("Rol: " + role);
            }
            return ResponseEntity.status(404).body("Usuario no encontrado");
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error: " + e.getMessage());
        }
    }

    @PostMapping("/logout")
    public ResponseEntity<?> logout(@RequestParam int idUser) {
        try {
            if (userService.isUserActive(idUser)) {
                return ResponseEntity.ok("Logout exitoso");
            }
            return ResponseEntity.status(401).body("Usuario no activo");
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error en logout");
        }
    }
}

package pe.edu.untels.controllers;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import pe.edu.untels.dtos.LoginRequestDTO;
import pe.edu.untels.dtos.LoginResponseDTO;
import pe.edu.untels.dtos.UserRegisterDTO;
import pe.edu.untels.entities.User;
import pe.edu.untels.entities.Role;
import pe.edu.untels.repositories.IRoleRepository;
import pe.edu.untels.servicesinterfaces.IUserService;
import java.time.LocalDateTime;
import java.util.Optional;

@RestController
@RequestMapping("/api/auth")
public class AuthController {
    @Autowired
    private IUserService userService;

    @Autowired
    private IRoleRepository roleRepository;

    @PostMapping("/login")
    public ResponseEntity<?> login(@RequestBody LoginRequestDTO loginRequestDTO) {
        try {
            LoginResponseDTO response = userService.login(loginRequestDTO);
            return ResponseEntity.ok(response);
        } catch (Exception e) {
            return ResponseEntity.status(401).body("Credenciales inválidas");
        }
    }

    @PostMapping("/register")
    public ResponseEntity<?> register(@RequestBody UserRegisterDTO registerDTO) {
        try {
            Optional<Role> roleOpt = roleRepository.findById(registerDTO.getIdRole());
            if (roleOpt.isEmpty()) {
                return ResponseEntity.status(400).body("Rol no encontrado");
            }

            User newUser = new User(
                registerDTO.getUsernameUser(),
                registerDTO.getPasswordUser(),
                registerDTO.getEmailUser(),
                true,
                LocalDateTime.now(),
                roleOpt.get()
            );

            User createdUser = userService.createUser(newUser);
            return ResponseEntity.status(201).body("Usuario registrado exitosamente con ID: " + createdUser.getIdUser());
        } catch (RuntimeException e) {
            return ResponseEntity.status(400).body(e.getMessage());
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error en el registro: " + e.getMessage());
        }
    }

    @GetMapping("/validate-role/{idUser}")
    public ResponseEntity<?> validateRole(@PathVariable int idUser) {
        try {
            var userOpt = userService.getUserById(idUser);
            if (userOpt.isPresent()) {
                String role = userOpt.get().getRole().getNameRole();
                return ResponseEntity.ok("Rol: " + role);
            }
            return ResponseEntity.status(404).body("Usuario no encontrado");
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error: " + e.getMessage());
        }
    }

    @PostMapping("/logout")
    public ResponseEntity<?> logout(@RequestParam int idUser) {
        try {
            if (userService.isUserActive(idUser)) {
                return ResponseEntity.ok("Logout exitoso");
            }
            return ResponseEntity.status(401).body("Usuario no activo");
        } catch (Exception e) {
            return ResponseEntity.status(500).body("Error en logout");
        }
    }
}

package pe.edu.untels.dtos;

public class UserRegisterDTO {
    private String usernameUser;
    private String passwordUser;
    private String emailUser;
    private int idRole;

    public UserRegisterDTO() {}

    public UserRegisterDTO(String usernameUser, String passwordUser, String emailUser, int idRole) {
        this.usernameUser = usernameUser;
        this.passwordUser = passwordUser;
        this.emailUser = emailUser;
        this.idRole = idRole;
    }

    public String getUsernameUser() { return usernameUser; }
    public void setUsernameUser(String usernameUser) { this.usernameUser = usernameUser; }

    public String getPasswordUser() { return passwordUser; }
    public void setPasswordUser(String passwordUser) { this.passwordUser = passwordUser; }

    public String getEmailUser() { return emailUser; }
    public void setEmailUser(String emailUser) { this.emailUser = emailUser; }

    public int getIdRole() { return idRole; }
    public void setIdRole(int idRole) { this.idRole = idRole; }
}

